framework_css:
:root {
  /* Color system */
  --color-primary: #3654A4;       /* Main brand blue (header/footer) */
  --color-primary-alt: #2C3E70;   /* Darker blue for text/hover */
  --color-accent: #D33434;        /* Accent red */

  --color-neutral-0: #FFFFFF;     /* White */
  --color-neutral-1: #F5F5F5;     /* Light background */
  --color-neutral-2: #DDDDDD;     /* Borders/dividers */
  --color-neutral-3: #8A8A8A;     /* Muted text */
  --color-neutral-4: #555555;     /* Body text */

  --color-success: #2E7D32;
  --color-error: #C62828;
  --color-warning: #ED6C02;
  --color-info: #0277BD;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', monospace;

  --font-size-h1: 28px;
  --font-size-h2: 22px;
  --font-size-h3: 18px;
  --font-size-body: 15px;
  --font-size-small: 13px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  --layout-max-width: 1180px;
  --header-height-desktop: 72px;
}

/* Reset & base layout */

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-4);
  background-color: var(--color-neutral-1);
}

.site-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-neutral-0);
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

/* Header */

.site-header {
  background-color: var(--color-primary);
  color: #FFFFFF;
}

.top-bar {
  background-color: var(--color-primary);
}

.top-bar-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-3);
  height: var(--header-height-desktop);
  display: flex;
  align-items: center;
}

/* Brand mark mimicking the solid logo block in the design */

.brand {
  flex: 0 0 auto;
}

.brand-link {
  display: flex;
  align-items: center;
  column-gap: var(--space-1);
  color: #FFFFFF;
}

.brand-mark {
  position: relative;
  width: 40px;
  height: 32px;
  border-radius: 2px;
  overflow: hidden;
  border: 2px solid #FFFFFF;
  display: inline-flex;
}

.brand-mark-block {
  flex: 1 1 50%;
}

.brand-mark-block--primary {
  background-color: var(--color-primary-alt);
}

.brand-mark-block--accent {
  background-color: var(--color-accent);
}

.brand-text {
  display: flex;
  flex-direction: column;
  line-height: 1.1;
}

.brand-name {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  font-size: 18px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.brand-tagline {
  font-size: 11px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  opacity: 0.8;
}

/* Primary navigation */

.primary-nav {
  flex: 1 1 auto;
  margin-left: var(--space-4);
}

.primary-nav-list {
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  column-gap: 24px;
  row-gap: 4px;
  margin: 0;
  padding: 0;
}

.primary-nav-item a {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-medium);
  font-size: 13px;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: #FFFFFF;
  text-decoration: none;
  padding-bottom: 4px;
  border-bottom: 2px solid transparent;
  white-space: nowrap;
}

.primary-nav-item a:hover,
.primary-nav-item a:focus {
  border-bottom-color: #FFFFFF;
}

.primary-nav-item a.is-active {
  border-bottom-color: var(--color-accent);
}

/* Right side of header (language switch) */

.header-meta {
  flex: 0 0 auto;
  margin-left: auto;
  font-family: var(--font-heading);
  font-size: 12px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  opacity: 0.9;
}

.language-switch {
  white-space: nowrap;
}

/* Main content shell */

.site-main {
  flex: 1 1 auto;
}

.page-shell {
  max-width: var(--layout-max-width);
  margin: var(--space-4) auto var(--space-5);
  padding: 0 var(--space-3) var(--space-5);
}

/* Base typography utilities matching the clean corporate style */

h1,
h2,
h3,
h4,
h5,
h6 {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  margin-top: 0;
  color: var(--color-primary-alt);
}

h1 {
  font-size: var(--font-size-h1);
  line-height: var(--line-height-tight);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-2);
}

.small-text {
  font-size: var(--font-size-small);
}

.muted-text {
  color: var(--color-neutral-3);
}

/* Footer */

.site-footer {
  background-color: var(--color-primary);
  color: rgba(255, 255, 255, 0.9);
}

.footer-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-3) var(--space-3) var(--space-4);
  text-align: center;
}

.footer-nav-list {
  list-style: none;
  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  column-gap: 24px;
  row-gap: 8px;
  margin: 0 0 var(--space-1);
  padding: 0;
}

.footer-nav-item a {
  font-family: var(--font-heading);
  font-size: 12px;
  letter-spacing: 0.16em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.9);
  text-decoration: none;
}

.footer-nav-item a:hover,
.footer-nav-item a:focus {
  text-decoration: underline;
}

.footer-copy {
  margin: 0;
  font-size: var(--font-size-small);
  color: rgba(255, 255, 255, 0.8);
}

/* Buttons (design system pattern, not instantiated in the framework HTML) */

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0 var(--space-2);
  min-height: 38px;
  border-radius: 2px;
  border: 1px solid var(--color-neutral-2);
  font-family: var(--font-heading);
  font-size: 13px;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  background-color: var(--color-neutral-0);
  color: var(--color-primary-alt);
  cursor: pointer;
}

.btn--primary {
  background-color: var(--color-primary);
  color: #FFFFFF;
  border-color: var(--color-primary);
}

.btn--primary:hover,
.btn--primary:focus {
  background-color: var(--color-primary-alt);
  border-color: var(--color-primary-alt);
}

.btn--ghost {
  background-color: transparent;
  color: #FFFFFF;
  border-color: rgba(255, 255, 255, 0.6);
}

/* Form controls (design system pattern) */

.form-group {
  margin-bottom: var(--space-2);
}

.form-label {
  display: block;
  font-weight: var(--font-weight-semibold);
  margin-bottom: 4px;
}

.form-control {
  width: 100%;
  min-height: 38px;
  padding: 8px 10px;
  border-radius: 2px;
  border: 1px solid var(--color-neutral-2);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
}

.form-control:focus {
  outline: none;
  border-color: var(--color-primary);
}

.form-control::placeholder {
  color: var(--color-neutral-3);
}

.form-helper-text {
  margin-top: 4px;
  font-size: var(--font-size-small);
  color: var(--color-neutral-3);
}

.form-error-text {
  margin-top: 4px;
  font-size: var(--font-size-small);
  color: var(--color-error);
}

/* Card / section container pattern */

.card {
  background-color: var(--color-neutral-0);
  border: 1px solid var(--color-neutral-2);
  border-radius: 2px;
  padding: var(--space-3);
}

.card + .card {
  margin-top: var(--space-2);
}

/* Simple vertical list pattern (e.g., for sidebar lists) */

.list-unstyled {
  list-style: none;
  margin: 0;
  padding: 0;
}

.list-vertical > li + li {
  margin-top: var(--space-1);
}

/* Responsive behavior */

@media (max-width: 960px) {
  .top-bar-inner {
    flex-wrap: wrap;
    height: auto;
    padding-top: var(--space-2);
    padding-bottom: var(--space-2);
  }

  .brand {
    margin-bottom: var(--space-1);
  }

  .primary-nav {
    order: 3;
    width: 100%;
    margin: var(--space-1) 0 0;
    overflow-x: auto;
  }

  .primary-nav-list {
    flex-wrap: nowrap;
    white-space: nowrap;
  }

  .header-meta {
    margin-left: 0;
    margin-top: var(--space-1);
  }

  .page-shell {
    margin-top: var(--space-3);
  }
}

@media (max-width: 600px) {
  .brand-mark {
    display: none;
  }

  .brand-name {
    font-size: 16px;
  }

  .brand-tagline {
    display: none;
  }

  .footer-inner {
    padding-left: var(--space-2);
    padding-right: var(--space-2);
  }
}
